(function(){window.tpCaptureCommunity||(window.tpCaptureCommunity=function(e){if(!(!e||!e.service||!e.price)){try{if(localStorage.getItem("tp_benchmark_optout")==="1")return}catch{}var o="tp_contributed_"+e.service+"_"+Math.round(e.price);try{localStorage.getItem(o)!=="true"&&fetch("/api/community-quote",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({price:e.price,material:e.material||"",city:e.city||"",stateCode:e.stateCode||"",roofSize:e.roofSize||0,serviceType:e.service,scopeConfirmed:e.scopeConfirmed||0,scopeTotal:e.scopeTotal||0,verdict:e.verdict||"",source:"auto"})}).then(function(c){if(c&&c.ok)try{localStorage.setItem(o,"true")}catch{}}).catch(function(){})}catch{}try{if(document.querySelector(".tp-benchmark-footnote"))return;var t=e.anchorEl||document.querySelector("[data-verdict]")||document.querySelector(".verdict-card")||document.querySelector(".pe-verdict")||document.querySelector(".cmp-verdict")||document.querySelector("h1")||document.body;if(!t)return;var r=document.createElement("div");r.className="tp-benchmark-footnote",r.style.cssText="padding:8px 14px; margin:8px auto 16px; font-size:12px; color:#94a3b8; text-align:center; max-width:720px;";var n=e.city?String(e.city).replace(/[<>&]/g,""):"your area";r.innerHTML="&#10003; Added to our anonymized local benchmark for "+n+`. No personal info shared. <a href="#" onclick="event.preventDefault();if(confirm('Exclude future analyses from anonymized benchmarks?')){localStorage.setItem('tp_benchmark_optout','1');this.parentNode.innerHTML='&#10003; You have opted out.';}" style="color:#94a3b8; text-decoration:underline; margin-left:6px;">opt out</a>`,t.parentNode?t.parentNode.insertBefore(r,t.nextSibling):t.appendChild(r)}catch{}}})})();
